@startuml
left to right direction
skinparam packageStyle rectangle
skinparam class {
  BackgroundColor White
  ArrowColor Black
  BorderColor Black
  FontColor Black
}

class "Acai" as Acai {
  <<abstract>>
  [
    String descricao
    Tamanho tamanho
    double getPreco()
    String getDescricao()
    Tamanho getTamanho()
  ]
}

class "Tamanho" as Tamanho {
  [
    PEQUENO
    MEDIO
    GRANDE
  ]
}

class "Morango" as Morango {
  [
    double preco
    double preco
    double getPreco()
    double getPreco()
  ]
}

class "AcaiNaBarca" as AcaiNaBarca {
  [
    Morango morango
    double getPreco()
  ]
}

class "AcaiNaTigela" as AcaiNaTigela {
  [
    Morango morango
    double getPreco()
  ]
}

class "AcaiNoCopo" as AcaiNoCopo {
  [
    Morango morango
    double getPreco()
  ]
}

class "AcaiNaBarcaComMorango" as AcaiNaBarcaComMorango {
  [
    AcaiNaBarca acaiNaBarca
    Morango morango
    double getPreco()
  ]
}

class "AcaiNaTigelaComMorango" as AcaiNaTigelaComMorango {
  [
    AcaiNaTigela acaiNaTigela
    Morango morango
    double getPreco()
  ]
}

class "AcaiNoCopoComMorango" as AcaiNoCopoComMorango {
  [
    AcaiNoCopo acaiNoCopo
    Morango morango
    double getPreco()
  ]
}

class "AcaiNaBarcaComMorangoEleiteEmPo" as AcaiNaBarcaComMorangoEleiteEmPo {
  [
    AcaiNaBarca acaiNaBarca
    Morango morango
    LeiteEmPo leiteEmPo
    double getPreco()
  ]
}

class "LeiteEmPo" as LeiteEmPo {
  [
    double preco
    double getPreco()
  ]
}

note right of Acai
  Método abstrato que deve ser
  implementado por toda Classe
  que herda de Acai
end note

Acai <|-- AcaiNaBarca
Acai <|-- AcaiNaTigela
Acai <|-- AcaiNoCopo
Acai <|-- AcaiNaBarcaComMorango
Acai <|-- AcaiNaTigelaComMorango
Acai <|-- AcaiNoCopoComMorango
Acai <|-- AcaiNaBarcaComMorangoEleiteEmPo

AcaiNaBarca ..> AcaiNaBarcaComMorango
AcaiNaTigela ..> AcaiNaTigelaComMorango
AcaiNoCopo ..> AcaiNoCopoComMorango
AcaiNaBarca ..> AcaiNaBarcaComMorangoEleiteEmPo
Morango ..> AcaiNaBarcaComMorango
Morango ..> AcaiNaTigelaComMorango
Morango ..> AcaiNoCopoComMorango
Morango ..> AcaiNaBarcaComMorangoEleiteEmPo
LeiteEmPo ..> AcaiNaBarcaComMorangoEleiteEmPo

@enduml
